previewCss:
.darma-loader-uiverse-react-atom-orbit {
  height: 20rem;
  width: 20rem;
  background-color: #212121;
  display: flex;
  justify-content: center;
  align-items: center;
}

.darma-loader-uiverse-react-atom-orbit__react-star {
position: relative;
width: 15rem;
display: flex;
justify-content: center;
align-items: center;
height: 15rem;
animation: darma-loader-uiverse-react-atom-orbit-rotate 3s infinite;
}

.darma-loader-uiverse-react-atom-orbit__nucleus {
position: absolute;

transform: translate(-50%, -50%);
border-radius: 50%;
background: linear-gradient(#0738e8, cyan);
height: 2rem;
width: 2rem;
animation: darma-loader-uiverse-react-atom-orbit-rotate 1s linear infinite;
}

.darma-loader-uiverse-react-atom-orbit__electron {
position: absolute;
width: 15rem;
height: 6rem;
border-radius: 50%;
border: 0.3rem solid #00ffff;
animation: darma-loader-uiverse-react-atom-orbit-revolve 1s linear infinite;
}

.darma-loader-uiverse-react-atom-orbit__electron1::before,
.darma-loader-uiverse-react-atom-orbit__electron2::before,
.darma-loader-uiverse-react-atom-orbit__electron3::before {
content: "";
position: absolute;
top: 60%;
left: 100%;
transform: translate(-50%, -50%);
width: 1rem;
height: 1rem;
background-color: cyan;
border-radius: 50%;
animation: darma-loader-uiverse-react-atom-orbit-moveElectron 1s infinite;
}
.darma-loader-uiverse-react-atom-orbit__electron2 {
transform: rotate(60deg);
animation-delay: -0.66s;
}
.darma-loader-uiverse-react-atom-orbit__electron2::before {
animation-delay: -0.66s;
}

.darma-loader-uiverse-react-atom-orbit__electron3 {
transform: rotate(-60deg);
}

@keyframes darma-loader-uiverse-react-atom-orbit-rotate {
from {
transform: rotate(0deg);
}
to {
transform: rotate(360deg) scale3d(1.1, 1.1, 0);
}
}

@keyframes darma-loader-uiverse-react-atom-orbit-revolve {
0% {
border-color: #00ffff9c;
border-right: transparent;
}
25% {
border-color: #00ffff9c;
border-bottom-color: transparent;
}
50% {
border-color: #00ffff9c;
border-left-color: transparent;
}
75% {
border-color: #00ffff9c;
border-top-color: transparent;
}
100% {
border-color: #00ffff9c;
border-right-color: transparent;
}
}

@keyframes darma-loader-uiverse-react-atom-orbit-moveElectron {
0% {
top: 60%;
left: 100%;
}
25% {
top: 100%;
left: 60%;
}
50% {
top: 60%;
left: 0%;
}
75% {
top: 0%;
left: 60%;
}
100% {
top: 60%;
left: 100%;
}
}

